// ParseDatacenter extracts the datacenter suffix from a Mailchimp API key.
// Mailchimp keys have the format "{32-hex}-{dc}" where the trailing token
// after the last "-" is the datacenter (e.g. "us6", "us21"). The suffix
// determines the API host: https://{dc}.api.mailchimp.com/3.0.
//
// Returns "" if the key has no recognizable suffix; callers should fall back
// to MAILCHIMP_DC or surface an error in doctor.
func ParseDatacenter(apiKey string) string {
	idx := strings.LastIndex(apiKey, "-")
	if idx < 0 || idx == len(apiKey)-1 {
		return ""
	}
	dc := apiKey[idx+1:]
	// Mailchimp datacenter codes are short (us1-us21, plus a few European
	// shards). Reject anything that obviously isn't a dc tag — protects
	// against keys that contain a literal "-" mid-token.
	if len(dc) < 2 || len(dc) > 6 {
		return ""
	}
	for i := 0; i < len(dc); i++ {
		c := dc[i]
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9')) {
			return ""
		}
	}
	return dc
}
